import { ChatFlow } from 'flowise/dist';

const detectTokenOverflow = (flow: ChatFlow) => {
  const nodes = flow.data.nodes;
  const llmNodes = nodes.filter(n => n.data?.type?.includes('LLM'));

  llmNodes.forEach(node => {
    const config = node.data.node?.template?.llmchain;
    if (config?.memory?.type === 'BufferMemory') {
      console.warn(`⚠️ BufferMemory detected in ${node.data.id} - Token overflow risk HIGH`);
    }

    const inputEdges = flow.data.edges?.filter(e => e.target === node.data.id) || [];
    if (inputEdges.length > 3) {
      console.error(`🚨 ${node.data.id}: ${inputEdges.length} inputs = Context explosion risk`);
    }
  });
};

const detectRetrievalBloat = (flow: ChatFlow) => {
  const retrievers = flow.data.nodes.filter(n => 
    n.data?.type?.includes('Retriever') || 
    n.data?.type?.includes('Vector')
  );

  retrievers.forEach(retriever => {
    const config = retriever.data.node?.template;
    const kValue = config?.k || config?.topK || 4;

    if (kValue > 5) {
      console.error(`🚨 ${retriever.data.id}: k=${kValue} too high. Max recommended: 5`);
    }

    if (!config?.metadataField && !config?.filter) {
      console.warn(`⚠️ ${retriever.data.id}: No relevance filtering configured`);
    }
  });
};

const detectContextHandoffs = (flow: ChatFlow) => {
  const agentNodes = flow.data.nodes.filter(n => 
    n.data?.type?.includes('Agent') || 
    n.data?.type?.includes('MultiAgent')
  );

  const edges = flow.data.edges || [];
  agentNodes.forEach((agent, idx) => {
    const outgoing = edges.filter(e => e.source === agent.data.id);
    const incoming = edges.filter(e => e.target === agent.data.id);

    if (incoming.length > 0 && !agent.data.node?.template?.sharedMemory) {
      console.error(`🚨 ${agent.data.id}: Agent handoff without shared memory!`);
    }

    if (outgoing.length > 1) {
      console.warn(`⚠️ ${agent.data.id}: Fan-out detected - context divergence risk`);
    }
  });
};

