// Add as Custom Function Node in Flowise
const truncateContext = async (input: any, modelMaxTokens: number = 128000) => {
  const { history, currentInput, model } = input;
  const tokenizer = require('@xenova/transformers').tokenizer;

  let totalTokens = tokenizer.encode(currentInput).length;
  const messages = history.messages.slice().reverse();

  for (let i = 0; i < messages.length; i++) {
    const msgTokens = tokenizer.encode(messages[i].content).length;
    if (totalTokens + msgTokens > modelMaxTokens * 0.8) break;
    totalTokens += msgTokens;
  }

  return {
    truncatedHistory: messages.slice(0, i).reverse(),
    tokensUsed: totalTokens,
    tokensSaved: history.messages.length - i
  };
};

