// Custom Tool Node for context bridging
const createContextBridge = (flowId: string) => {
  return async (input: any) => {
    const redis = require('redis').createClient();
    const key = `flowise:context:${flowId}`;

    // Store current context
    await redis.set(key, JSON.stringify({
      timestamp: Date.now(),
      history: input.history,
      agentState: input.agentState,
      sessionId: input.sessionId
    }), 'EX', 3600);

    // Load for next agent
    const downstreamContext = await redis.get(key);
    return {
      ...input,
      sharedContext: JSON.parse(downstreamContext || '{}'),
      bridgeActive: true
    };
  };
};

