import { Vex } from '@vex_dev/sdk';
import { ChatFlow } from 'flowise/dist';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY
});

// Add Vex callback to Flowise chatflow
const instrumentFlowise = (chatflow: ChatFlow) => {
  chatflow.callbacks.push({
    onNodeExecute: async (nodeId, input, output, tokensUsed) => {
      const alert = await vex.check({
        framework: 'flowise',
        nodeId,
        inputTokens: tokensUsed.input,
        outputTokens: tokensUsed.output,
        contextRatio: tokensUsed.input / 128000,
        flowId: chatflow.id
      });

      if (alert.severity === 'CRITICAL') {
        // Auto-apply fix
        await vex.remediate('context_overflow', {
          nodeId,
          fix: 'truncate_history',
          maxTokens: 100000
        });
      }
    },
    onFlowComplete: (execution) => {
      vex.reportFlowMetrics(execution);
    }
  });

  return chatflow;
};

// Usage in Flowise server
export default instrumentFlowise;
